/// <summary>
/// This method is the onLookup form control event handler for VendInvoiceInfoTable_ETGTERMONumber
/// </summary>
/// <param name="sender">FormControl</param>
/// <param name="e">FormControlEventArgs</param>
[FormControlEventHandler(formControlStr(VendEditInvoice, ETGTERMONumberLineView), FormControlEventType::Lookup)]
public static void VendInvoiceInfoTable_ETGTERMONumber_OnLookup(FormControl sender, FormControlEventArgs e)
{
    ETGTERMONumberTable::lookupTERMONumberTable(sender, ETGImportOrExport::Import);
    FormControlCancelableSuperEventArgs cancelSuperEventArgs = e as FormControlCancelableSuperEventArgs;
    cancelSuperEventArgs.CancelSuperCall();
 }

[FormDataSourceEventHandler(formDataSourceStr(VendEditInvoice, VendInvoiceInfoTable), FormDataSourceEventType::Initialized)]
public static void VendInvoiceInfoTable_OnInitialized(FormDataSource sender, FormDataSourceEventArgs e)
{
    FormDataSource vendInvoiceInfoTable_ds = sender;


    FormDataObject documentDateField = vendInvoiceInfoTable_ds.object(fieldNum(VendInvoiceInfoTable, ETGDocumentDate));

    if (documentDateField)
    {

        if (ETG_Parameters::find().ETGDocumentDate == NoYes::Yes)
        {
            documentDateField.mandatory(true);  
        }
        else
        {
            documentDateField.mandatory(false); 
        }


    }
}
